class Solution:
    def restoreString(self, s, indices):
        pairs = sorted(range(len(s)), key=lambda i: indices[i])
        return ''.join(s[i] for i in pairs)

solutions.python:
class Solution:
    def restoreString(self, s, indices):
        result = [''] * len(s)
        for i, pos in enumerate(indices):
            result[pos] = s[i]
        return ''.join(result)

